import { Component } from '@angular/core';
import { AuthService } from '../_services/auth.service';

@Component({
  selector: 'register',
  templateUrl: './register.component.html',
  styleUrls: ['./register.component.css']
})
export class RegisterComponent {

model: any = {};

constructor(private authService: AuthService) {}

register(){
  this.authService.register(this.model).subscribe(()=>{
    console.log("kullanıcı oluşturuldu");
  })
}

}
<div class="container" style="margin-top: 150px;">
<div class="row">
  <div class="col-6">
    <form (ngSubmit)="register()">
      <h2>Register</h2>
      <hr>
      <div class="form-group">
        <input type="text" name="name" [(ngModel)]="model.name" class="form-control" placeholder="Name">
      </div>
      <div class="form-group">
        <input type="text" name="username" [(ngModel)]="model.username" class="form-control" placeholder="UserName">
      </div>
      <div class="form-group">
        <input type="email" name="email" [(ngModel)]="model.email" class="form-control" placeholder="Email">
      </div>
      <div class="form-group">
        <input type="password" name="password" [(ngModel)]="model.password" class="form-control" placeholder="Password">
      </div>
      <button class="btn btn-primary btn-block" type="submit">Submit</button>
    </form>
  </div>
</div>
</div>
